var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"<color=#ffd34c>관리국 재건 도시 ARC-PW1 외곽</color>","JPN":"<color=#ffd34c>管理局再建都市ARC-PW1の外郭</color>","ENG":"<color=#ffd34c>Administration Rebuilt City ARC-PW1 Outskirts</color>","TWN":"<color=#ffd34c>管理局重建城市 ARC-PW1近郊</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이 근처에서 냄새가 나는데…….","JPN":"この辺りからだ……","ENG":"I smell something around here...","TWN":"這附近有味道……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"지독한 <color=#ffd34c>악령</color>의 냄새가…….","JPN":"<color=#ffd34c>悪霊</color>のひどい匂いがする……","ENG":"A foul stench of an <color=#ffd34c>evil spirit</color>...","TWN":"強烈的<color=#ffd34c>惡靈</color>的氣味……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"여기구나!","JPN":"ここか！","ENG":"Found it!","TWN":"在這裡啊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이 녀석이 마지막인가?","JPN":"こいつが最後か？","ENG":"Is this the last one?","TWN":"這傢伙是最後一個了吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"침식 쐐기도 파괴했고……","JPN":"侵食楔も破壊しましたし……","ENG":"I've destroyed the Corrupted Wedge...","TWN":"侵蝕釘也破壞了……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이제 악령들이 여러분을 괴롭힐 일은 없을 겁니다.","JPN":"もう悪霊が皆さんを苦しめることはないでしょう。","ENG":"Now, these evil spirits won't trouble you anymore.","TWN":"現在惡靈們不會再來騷擾你們了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"안심하시길.","JPN":"ご安心ください。","ENG":"You can rest easy.","TWN":"請放心。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"감사합니다. 수녀님. 이 은혜를 어찌 갚아야 할지…….","JPN":"ありがとうございます、シスター。このご恩に報いるにはどうすれば……","ENG":"Thank you, Sister. I don't know how we could ever repay you...","TWN":"謝謝你，修女。我真不知道該如何報答這份恩情……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"해야 할 일을 했을 뿐이죠.","JPN":"己の役目を果たしただけです。","ENG":"I only did what needed to be done.","TWN":"我只是做了我該做的事而已。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"하지만 여러분들의 호의를 거절하는 건 예의가 아닌 법.","JPN":"ですが、みなさんのご厚意を断るのも失礼でしょう。","ENG":"But refusing a token of gratitude wouldn't be polite.","TWN":"但是拒絕大家的好意是不禮貌的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"자, 이건 악령이 깃든 땅을 정화하는 성수예요.","JPN":"どうぞ、こちらを。悪霊が巣くう地を浄化する聖水です。","ENG":"Here, this is holy water to cleanse the land of evil spirits.","TWN":"這是可以淨化惡靈的淨水。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"땅에 성수가 많이 스며들수록 악령들이 쉽게 접근하지 못할 겁니다.","JPN":"地に染み込んだ聖水が多くなるほど、悪霊がたやすく近寄れなくなります。","ENG":"The more you pour into the ground, the harder it will be for them to return.","TWN":"淨水滲入土地越多，惡靈就越難靠近。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"물론, 주님의 영험함을 담은 진품이죠.","JPN":"もちろん、主の神聖な力が込められている本物ですよ。","ENG":"And of course, it's the real deal with the Lord's power.","TWN":"當然，這可是蘊含了主的神奇力量的真品。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"직접 세례를 받은 성수라는 겁니까?","JPN":"直接洗礼を受けた聖水ということですか？","ENG":"You mean... it's been personally blessed?","TWN":"這是直接受洗的淨水嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"네. 직접 마셔도 효능이 있답니다.","JPN":"はい。飲んでも効果があるんですよ。","ENG":"Yes. You can even drink it for its restorative effects.","TWN":"是的，直接喝也有效果。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"무려, 지친 몸에 활력을 불어넣게 되죠.","JPN":"なんと、疲れた体に活力を吹き込んでくれるのです。","ENG":"In fact, it'll help reinvigorate a tired body.","TWN":"還能給疲憊的身體注入活力呢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"지친 몸에 활력을…….","JPN":"疲れた体に活力を……","ENG":"Reinvigorate a tired body...","TWN":"能為疲憊的身體注入活力……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"안 그래도 요즘 부쩍 몸이 무거워진 것 같았어.","JPN":"そういえば、最近体が重く感じるんだよな。","ENG":"Come to think of it, I have been feeling sluggish lately.","TWN":"最近確實感覺身體越來越沉重了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_B","text":{"KOREA":"저요! 그 성수, 제가 10병 사겠습니다!","JPN":"あの！　その聖水10本買います！","ENG":"I'll take ten bottles!","TWN":"那淨水，我要買10瓶！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"저도 살게요!","JPN":"私も買います！","ENG":"I'll buy some too!","TWN":"我也要買！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"개수가 얼마나 되죠? 저도 사고 싶어요!","JPN":"どれくらいあるんですか？　私も買いたい！","ENG":"How many do you have? I want one as well!","TWN":"數量有多少？我也想買！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"밀지 마! 수녀님이 곤란해하시잖아!","JPN":"押さないで！　シスターが困ってるでしょう！","ENG":"Hey, don't push! You're crowding her!","TWN":"不要推！修女都要被擠飛了！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAN_MOONLIGHT_NPC_B","face":"UNIT_IDLE"},"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"그만!","JPN":"やめなさい！","ENG":"Enough!","TWN":"住手！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"몇 주간 저희를 괴롭힌 심령 현상을 해결해 주신 수녀님에게 무슨 실례란 말입니까?","JPN":"何週間も私たちを困らせてきた心霊現象を解決してくださったシスターになんて失礼を！","ENG":"How can you be this rude after she resolved the haunting that plagued us for weeks?","TWN":"怎麼能對這麼修女這麼無禮呢？人家剛剛幫了我們大忙。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"추태를 보여 죄송합니다. 수녀님.","JPN":"お恥ずかしいところをお見せしてすみません、シスター。","ENG":"I apologize for their behavior, Sister.","TWN":"真是失禮了，修女。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"수녀님이 오신 것 또한, 주님께서 우릴 보살펴주신 덕분이겠지요.","JPN":"シスターがここに来られたのも、主が私たちをお守りくださっているからでしょう。","ENG":"Truly, the fact that you came to us must be the Lord's way of watching over us.","TWN":"修女能到我們這裡來，都是主在庇佑我們吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"맞습니다.","JPN":"そのとおりです。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"신실하신 여러분을 굽어살피시어 주님께서 저를 인도해 주신 겁니다.","JPN":"誠実なみなさんをご覧になり、主が私を導いてくださったのです。","ENG":"It is by His guidance that I was led to you.","TWN":"是主垂憐了虔誠的你們，引導了我。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이 병 안에는 주님의 축복을 받은 성수가 들어있습니다.","JPN":"このビンの中には、主に祝福された聖水が入っています。","ENG":"Inside these bottles is holy water imbued with His blessings.","TWN":"這瓶子裡裝著受到主祝福的淨水。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"여러분이 헌금으로 성의를 보여줄 때마다 주님의 축복은 강해지겠죠?","JPN":"みなさんが献金という形で誠意を示されるたびに、主の祝福はより一層強くなるでしょう。","ENG":"And with every generous offering you make, His blessings only grow stronger.","TWN":"每當你們透過奉獻表達誠意後，主的祝福就會更加強大的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"수녀님이 가고 나서 이런 일이 또 일어나면 어쩌지?","JPN":"シスターがここを去られた後、またこんなことが起きたらどうする？","ENG":"But what if something like this happens again after she leaves?","TWN":"如果修女走了之後，這種事情再發生怎麼辦？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"딱 한 병만 사는 건 어떨까?","JPN":"1本だけ買ってみるか？","ENG":"Maybe we should just get one bottle, just in case...","TWN":"只買一瓶怎麼樣？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"하, 하지만 헌금으로 성의를 보이는 건 사이비 종교에서…….","JPN":"で、でも献金で誠意を示すのはカルト宗教で……","ENG":"B-but asking for offerings in exchange for blessings... isn't that what cults do?","TWN":"但，但是用奉獻來表示誠意是邪教才會……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"그러고 보니 아직 대금을 받지 못했군요.","JPN":"そういえば、まだ代金をもらっていませんでしたね。","ENG":"Now that I think about it, I haven't received my payment yet.","TWN":"這麼說來，我還沒收到費用呢。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"이번 대금은…… 이 정도가 적당할 것 같네요.","JPN":"今回の代金は……このくらいが適当かと。","ENG":"For this job... this seems like a fair price.","TWN":"這次的費用……這個金額應該差不多。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L16_1","type":"dialog","speaker":"MAN_MOONLIGHT_NPC_A","text":{"KOREA":"네? 분명 의뢰를 드렸을 때는 이 가격이…….","JPN":"はい？　依頼した時はたしかこの価格では……","ENG":"Wait, when we first asked for your help, the fee was–","TWN":"什麼？明明委託的時候是這個價格……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAN_MOONLIGHT_NPC_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"여러분이 주님께 헌금할 비용을 추가했어요.","JPN":"皆さんが主に献金する分を追加しました。","ENG":"I've added a contribution to your offering to the Lord.","TWN":"大家為主獻上的奉獻金額增加了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"돈은 근심을 가져다주는 허울일 뿐, 진정한 축복은 헌금을 통해 찾아옵니다.","JPN":"お金は心配の種、本当の祝福は献金によってもたらされるのです。","ENG":"Money is nothing but a fleeting worry. True blessings come through offerings.","TWN":"錢只能帶來憂慮的虛名，真正的祝福是透過奉獻獲得的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"제가 여러분의 헌금을 받는 대신, 이 성수들을 전부 나눠드리도록 하죠.","JPN":"私が皆さんから献金をいただく代わりに、この聖水を全部さしあげましょう。","ENG":"So, instead of taking your offerings, I'll distribute these bottles of holy water to everyone here.","TWN":"我將把這些淨水全部分發給你們，以此回應你們的奉獻。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"그, 그런 뜻이…… 역시 수녀님이셔.","JPN":"そ、そんな意図が……さすがシスターだ。","ENG":"Th-that's what you meant... You truly are a saint, Sister.","TWN":"那，那意思是……不愧是修女。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"그래. 프랭크가 며칠 전에 악령이 우는 소리를 들었다며.","JPN":"そうだ。フランクが数日前に悪霊の鳴き声を聞いたそうじゃないか。","ENG":"Yeah... Frank said he heard the evil spirits crying just the other night.","TWN":"對了，法蘭克幾天前還聽到了惡靈的叫聲。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PEOPLE_MOONLIGHT_NPC_NULL","text":{"KOREA":"성수를 뿌리지 않으면 악령이 다시 우리를 괴롭힐지도…….","JPN":"聖水を撒いておかないと、また悪霊が私たちを苦しめるかも……","ENG":"If we don't spread the holy water, they might come back...","TWN":"如果不灑淨水，惡靈可能會再次來騷擾我們……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"여러분이 주님의 뜻을 깨달아서 무척이나 기쁩니다.","JPN":"皆さんが主の意思をわかってくださってとても嬉しいです。","ENG":"I'm glad you've come to understand the Lord's will.","TWN":"很高興你們領悟了主的旨意。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_QM","text":{"KOREA":"그럼, 저는 주님의 은혜가 필요한 곳으로 떠나도록 하죠.","JPN":"それでは、私は主の恩寵が必要なところへ向かうとします。","ENG":"Now then, I must go where His grace is needed next.","TWN":"那麼，我將去到其他需要主恩的地方。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_QM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>발렌티누스 수도원</color>의 퇴마 수녀, 루시아 릿지.","JPN":"<color=#ffd34c>バレンチヌス修道院</color>の退魔シスター、ルシア・リッジ。","ENG":"I'm Lucia Ridge, the exorcist nun of the <color=#ffd34c>Valentinus Monastery</color>.","TWN":"<color=#ffd34c>聖華倫修道院</color>的驅魔修女，露西卡·李奇。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"심령 현상이 일어날 때마다 저를 찾아주시길.","JPN":"心霊現象に頭を抱えているのなら、どうか私を訪ねてきてください。","ENG":"Whenever you face a haunting, you know where to find me.","TWN":"發生靈異現象時，請來找我。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};